import React, { useState } from "react";

export default function LaundryPage() {
  const [activeTab, setActiveTab] = useState("new");
  const clothTypes = ["Shirt", "Pant", "T-shirt", "Bedsheet", "Towel"];
  const [selectedClothes, setSelectedClothes] = useState([]);
  const [quantity, setQuantity] = useState(1);

  const toggleCloth = (cloth) => {
    setSelectedClothes((prev) =>
      prev.includes(cloth) ? prev.filter((c) => c !== cloth) : [...prev, cloth]
    );
  };

  const orders = [
    {
      id: "LAU-001",
      date: "Apr 2, 2024",
      items: "Shirt, Pant",
      status: "Completed",
      pickup: "Apr 4",
    },
    {
      id: "LAU-002",
      date: "Mar 28, 2024",
      items: "T-shirt, Bedsheet",
      status: "In Progress",
      pickup: "Apr 1",
    },
  ];

  return (
    <div className="space-y-8">
      {/* Header */}
      <div className="glass-card p-8 space-y-2">
        <h1 className="text-3xl font-bold text-slate-900">🧺 Laundry Service</h1>
        <p className="text-slate-600">Schedule laundry pickup & delivery</p>
      </div>

      {/* Tabs */}
      <div className="glass-card p-4 flex gap-4">
        <button
          onClick={() => setActiveTab("new")}
          className={`px-6 py-3 rounded-lg font-semibold transition-all ${
            activeTab === "new"
              ? "tab-active bg-blue-100 text-blue-700"
              : "tab-inactive hover:bg-slate-100"
          }`}
        >
          ➕ New Order
        </button>
        <button
          onClick={() => setActiveTab("track")}
          className={`px-6 py-3 rounded-lg font-semibold transition-all ${
            activeTab === "track"
              ? "tab-active bg-blue-100 text-blue-700"
              : "tab-inactive hover:bg-slate-100"
          }`}
        >
          📦 My Orders
        </button>
      </div>

      {/* New Order Tab */}
      {activeTab === "new" && (
        <div className="space-y-8">
          {/* Cloth Selection */}
          <div className="glass-card p-8 space-y-4">
            <h2 className="text-2xl font-bold text-slate-900">Select Clothes</h2>

            <div className="grid grid-cols-2 md:grid-cols-5 gap-4">
              {clothTypes.map((cloth) => (
                <button
                  key={cloth}
                  onClick={() => toggleCloth(cloth)}
                  className={`p-4 rounded-xl font-semibold transition-all ${
                    selectedClothes.includes(cloth)
                      ? "glass-card-hover bg-blue-100 border-2 border-blue-600 text-blue-700"
                      : "glass-card hover:bg-slate-50"
                  }`}
                >
                  {cloth}
                </button>
              ))}
            </div>
          </div>

          {/* Quantity */}
          <div className="glass-card p-8 space-y-4">
            <h2 className="text-2xl font-bold text-slate-900">Quantity</h2>

            <div className="flex items-center gap-4">
              <label className="font-semibold text-slate-700">Weight (kg):</label>
              <div className="flex items-center gap-3">
                <button
                  onClick={() => setQuantity(Math.max(1, quantity - 1))}
                  className="w-10 h-10 rounded-lg bg-red-100 text-red-600 font-bold hover:bg-red-200"
                >
                  −
                </button>
                <span className="text-2xl font-bold text-slate-900 w-16 text-center">
                  {quantity}
                </span>
                <button
                  onClick={() => setQuantity(quantity + 1)}
                  className="w-10 h-10 rounded-lg bg-green-100 text-green-600 font-bold hover:bg-green-200"
                >
                  +
                </button>
              </div>
            </div>
          </div>

          {/* Information */}
          <div className="glass-card p-8">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div className="space-y-2">
                <p className="font-bold text-slate-900">📍 Pickup</p>
                <p className="text-slate-600">Within 24 hours from order</p>
              </div>
              <div className="space-y-2">
                <p className="font-bold text-slate-900">⏱️ Processing</p>
                <p className="text-slate-600">Ready in 48 hours</p>
              </div>
              <div className="space-y-2">
                <p className="font-bold text-slate-900">💰 Price</p>
                <p className="text-slate-600">₹{quantity * 50} for {quantity}kg</p>
              </div>
            </div>
          </div>

          {/* Order Button */}
          <button
            disabled={selectedClothes.length === 0}
            className="btn-primary w-full py-4 text-lg disabled:opacity-50"
          >
            Place Laundry Order
          </button>
        </div>
      )}

      {/* Track Orders Tab */}
      {activeTab === "track" && (
        <div className="space-y-4">
          {orders.map((order) => (
            <div key={order.id} className="glass-card p-6 space-y-3">
              <div className="flex items-center justify-between">
                <div>
                  <p className="font-bold text-slate-900">{order.id}</p>
                  <p className="text-sm text-slate-600">{order.date}</p>
                </div>
                <span
                  className={`px-4 py-2 rounded-full font-semibold text-sm ${
                    order.status === "Completed"
                      ? "bg-emerald-100 text-emerald-700"
                      : "bg-amber-100 text-amber-700"
                  }`}
                >
                  {order.status}
                </span>
              </div>

              <div className="space-y-1 text-sm">
                <p className="text-slate-700">
                  <span className="font-semibold">Items:</span> {order.items}
                </p>
                <p className="text-slate-700">
                  <span className="font-semibold">Pickup Date:</span> {order.pickup}
                </p>
              </div>

              <div className="w-full bg-slate-200 rounded-full h-2">
                <div
                  className={`h-2 rounded-full ${
                    order.status === "Completed" ? "bg-emerald-500 w-full" : "bg-blue-500 w-2/3"
                  }`}
                ></div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
